INSERT INTO PromptResponse (id_response, prompt_id, content, tokens_prompt, tokens_response) VALUES
('d4e5f6a7-0004-4000-8000-000000000001', 'c3d4e5f6-0003-4000-8000-000000000001', 'Revisión de código completada. Se encontraron 3 problemas principales: primero, la función principal carece de validación de entradas, lo que puede causar errores silenciosos; segundo, se detectó concatenación directa de strings en una consulta SQL, exponiendo la aplicación a inyección; tercero, los nombres de variables como "x" y "tmp" dificultan la lectura. Se recomienda agregar tipado estático, implementar un logger estructurado y cubrir los flujos alternativos con pruebas unitarias.', 210, 180),
('d4e5f6a7-0004-4000-8000-000000000002', 'c3d4e5f6-0003-4000-8000-000000000002', 'Artículo generado con éxito. Título: "10 Estrategias de SEO para 2025 que Realmente Funcionan". El artículo incluye introducción que contextualiza el tema, seis secciones con subtítulos H2 y tres subsecciones H3 cada una, ejemplos de casos de uso reales, una sección de errores comunes a evitar, y un llamado a la acción final invitando al lector a suscribirse al newsletter. Palabras totales: 1.420. Densidad de keyword principal: 1,8%.', 195, 310),
('d4e5f6a7-0004-4000-8000-000000000003', 'c3d4e5f6-0003-4000-8000-000000000003', 'Resumen ejecutivo completado. El documento analiza la expansión de mercado hacia tres regiones de América Latina durante el primer semestre. Los puntos clave son: crecimiento del 34% en México, necesidad de ajuste regulatorio en Brasil y oportunidad de entrada en Colombia con bajo costo de adquisición. El principal elemento de acción es asignar un equipo local en São Paulo antes del Q3. El riesgo más relevante identificado es la volatilidad cambiaria en Argentina.', 280, 240),
('d4e5f6a7-0004-4000-8000-000000000004', 'c3d4e5f6-0003-4000-8000-000000000004', 'Correo de marketing generado. Asunto: "Última oportunidad: tu flujo de trabajo cambia hoy". El cuerpo inicia con una pregunta que interpela directamente al lector sobre su mayor problema diario, seguida por la propuesta de valor del producto en dos oraciones claras. El CTA es "Empieza gratis en 60 segundos" con enlace destacado. La posdata indica que la oferta de onboarding gratuito expira en 48 horas. Tono conversacional y directo.', 175, 220),
('d4e5f6a7-0004-4000-8000-000000000005', 'c3d4e5f6-0003-4000-8000-000000000005', 'Respuesta de soporte generada. El agente reconoce la frustración del cliente por el cobro duplicado, ofrece disculpas sinceras y explica el proceso de reembolso paso a paso: verificación en 24 horas, notificación por correo y acreditación en 5 días hábiles. Se incluye un número de caso para seguimiento y una oferta de descuento del 10% en la próxima compra como compensación. Tono empático y profesional durante toda la respuesta.', 150, 190),
('d4e5f6a7-0004-4000-8000-000000000006', 'c3d4e5f6-0003-4000-8000-000000000006', 'Preguntas de entrevista generadas para el puesto de Product Manager Senior. Se incluyeron 5 preguntas conductuales usando el método STAR, tales como describir una situación en que debió priorizar con información incompleta. Se agregaron 4 preguntas técnicas sobre métricas de producto y frameworks de priorización, y 3 escenarios de resolución de problemas que simulan situaciones reales de conflicto entre equipos. También se añadió una pregunta de ajuste cultural sobre gestión del fracaso.', 130, 185),
('d4e5f6a7-0004-4000-8000-000000000007', 'c3d4e5f6-0003-4000-8000-000000000007', 'Análisis de datos completado. El conjunto de datos de 1.200 registros muestra una media de ventas de 4.320 unidades mensuales con una desviación estándar de 890. Se identificó un patrón claro de estacionalidad con picos en noviembre y marzo. La anomalía más notable es una caída del 62% en ventas durante la semana del 14 de julio, consistente con el cierre temporal reportado en el registro de operaciones. Se recomienda excluir esa semana del modelo predictivo.', 300, 390),
('d4e5f6a7-0004-4000-8000-000000000008', 'c3d4e5f6-0003-4000-8000-000000000008', 'Resumen legal completado. El contrato de prestación de servicios entre las partes estipula una vigencia de 12 meses renovables automáticamente. Los términos más relevantes incluyen una cláusula de exclusividad en el territorio nacional, penalización del 15% sobre el valor del contrato por terminación anticipada sin causa justificada, y obligación de confidencialidad por 3 años posteriores a la vigencia. Se identificó una cláusula de arbitraje que limita la jurisdicción a la ciudad de Madrid, lo cual puede ser desventajoso para la parte contratante.', 260, 255),
('d4e5f6a7-0004-4000-8000-000000000009', 'c3d4e5f6-0003-4000-8000-000000000009', 'Post de blog generado. Título: "Por qué tu estrategia de contenidos está fallando (y cómo arreglarlo hoy)". El post abre con una anécdota cercana al lector, desarrolla tres causas comunes del fracaso en contenidos con ejemplos reales, propone un framework de cinco pasos para reorientar la estrategia y cierra con la pregunta: ¿cuál de estos errores reconoces en tu negocio? Extensión total: 980 palabras. Tono directo y empático.', 200, 410),
('d4e5f6a7-0004-4000-8000-000000000010', 'c3d4e5f6-0003-4000-8000-000000000010', 'Documentación de API generada para el endpoint POST /api/v2/orders. La descripción explica el propósito de creación de pedidos. Los parámetros requeridos son customer_id (entero), items (arreglo de objetos con product_id y quantity) y shipping_address (cadena). La autenticación es mediante Bearer token en el header Authorization. Se detallaron los códigos de respuesta 201 (creado), 400 (datos inválidos), 401 (no autorizado) y 500 (error del servidor), con descripción en texto de cada uno y ejemplo del cuerpo de respuesta esperado.', 220, 285),
('d4e5f6a7-0004-4000-8000-000000000011', 'c3d4e5f6-0003-4000-8000-000000000011', 'Esquema de paper creado para el tema "Impacto del aprendizaje automático en el diagnóstico temprano de enfermedades cardiovasculares". Abstract resume el problema, metodología propuesta y hallazgos esperados en 150 palabras. La revisión de literatura cubre 4 subtemas: modelos existentes, datasets disponibles, limitaciones actuales y brechas de investigación. La metodología propone un diseño experimental con validación cruzada. Los hallazgos anticipados incluyen comparación de tres algoritmos. La conclusión integra implicaciones clínicas y líneas futuras.', 190, 265),
('d4e5f6a7-0004-4000-8000-000000000012', 'c3d4e5f6-0003-4000-8000-000000000012', 'Traducción completada del inglés al español con adaptación cultural. El texto original usaba el modismo "bite the bullet" que fue adaptado como "apretar los dientes y seguir adelante" para mantener el tono coloquial en el contexto de un artículo de superación personal. Las referencias a medidas imperiales fueron convertidas a sistema métrico. El nivel de formalidad se ajustó de "you" informal americano a un "tú" apropiado para audiencia latinoamericana joven. Extensión traducida: 850 palabras.', 120, 155),
('d4e5f6a7-0004-4000-8000-000000000013', 'c3d4e5f6-0003-4000-8000-000000000013', 'Guía de migración de Python a TypeScript completada. Se describieron las equivalencias entre listas de Python y arrays de TypeScript, los decoradores vs. los modificadores de acceso, y el manejo de excepciones en ambos lenguajes. Las trampas más comunes identificadas son la tipificación de None vs. null/undefined y la diferencia en el alcance de variables con let/const vs. la asignación directa de Python. Los pasos de validación incluyen ejecutar el linter de TypeScript y comparar las salidas de ambas versiones con los mismos datos de prueba.', 255, 325),
('d4e5f6a7-0004-4000-8000-000000000014', 'c3d4e5f6-0003-4000-8000-000000000014', 'Evaluación de síntomas completada. Los síntomas descritos (fatiga persistente, dolor de cabeza matutino y ligero mareo al ponerse de pie) pueden estar asociados con deshidratación crónica, hipotensión ortostática o déficit de hierro. Se recomienda consultar a un médico si los síntomas persisten más de una semana o si se añaden palpitaciones o pérdida del conocimiento. Recomendaciones generales: aumentar la ingesta de agua a 2 litros diarios, evitar levantarse bruscamente y revisar el historial de análisis de sangre recientes. Nota: esta información no reemplaza la consulta médica.', 148, 205),
('d4e5f6a7-0004-4000-8000-000000000015', 'c3d4e5f6-0003-4000-8000-000000000015', 'Reporte financiero generado para el período Q1-Q2 2025. El ratio de liquidez corriente es de 2.3, indicando buena capacidad de pago a corto plazo. El margen neto del 8.4% está por encima del promedio sectorial del 6.1%. La tendencia de ingresos muestra crecimiento del 18% interanual, concentrado en el segmento enterprise. El principal riesgo identificado es la concentración del 42% de los ingresos en tres clientes, lo que genera vulnerabilidad ante la pérdida de cualquiera de ellos. Se recomienda una estrategia de diversificación de cartera para el H2.', 240, 355),
('d4e5f6a7-0004-4000-8000-000000000016', 'c3d4e5f6-0003-4000-8000-000000000016', 'Calendario de contenidos generado para Instagram en el nicho de bienestar y salud mental. Los primeros 7 días alternan entre carruseles educativos, historias de testimonio y reels de tips rápidos. Los captions están escritos en tono cercano y motivador, con preguntas al cierre para fomentar comentarios. La semana 2 introduce una serie de "mitos vs. realidades". Los hashtags recomendados se dividen en tres bloques: de alta competencia, de nicho y de marca propia. El calendario incluye dos publicaciones por día: una en feed y una en Stories.', 160, 225),
('d4e5f6a7-0004-4000-8000-000000000017', 'c3d4e5f6-0003-4000-8000-000000000017', 'Historia corta generada. Título: "El último tren". En un andén vacío a las 3 AM, Laura encuentra un billete de tren con su nombre y una fecha de hace veinte años. La historia sigue su decisión de abordar el tren y el reencuentro con una versión de sí misma que eligió un camino diferente. El conflicto central explora el arrepentimiento y la identidad. El desenlace es abierto, invitando al lector a decidir si Laura regresó o se quedó en ese otro presente. Extensión: 620 palabras. Género: realismo mágico.', 190, 260),
('d4e5f6a7-0004-4000-8000-000000000018', 'c3d4e5f6-0003-4000-8000-000000000018', 'Ruta de aprendizaje generada para programación en Rust desde nivel principiante. El plan está estructurado en 6 meses con 8 horas semanales de dedicación. El primer mes cubre sintaxis básica y manejo de memoria. El segundo y tercer mes profundizan en el sistema de tipos y la gestión de errores. Los meses 4 y 5 introducen concurrencia y desarrollo de APIs REST. El mes 6 propone un proyecto integrador: construir una CLI funcional. Los recursos recomendados son el libro oficial "The Rust Programming Language", Rustlings y ejercicios en Exercism.', 175, 235),
('d4e5f6a7-0004-4000-8000-000000000019', 'c3d4e5f6-0003-4000-8000-000000000019', 'PRD generado para la funcionalidad de notificaciones push. Las historias de usuario incluyen cuatro escenarios: usuario que activa notificaciones, usuario que personaliza preferencias, usuario que recibe alerta en tiempo real y usuario que desactiva notificaciones específicas. Los criterios de aceptación están redactados con el formato "dado/cuando/entonces". Las métricas de éxito son: tasa de opt-in superior al 45%, tasa de apertura de notificaciones mayor al 20% y tiempo de entrega menor a 3 segundos.', 180, 280),
('d4e5f6a7-0004-4000-8000-000000000020', 'c3d4e5f6-0003-4000-8000-000000000020', 'Análisis competitivo completado para empresa de software B2B en el sector de gestión de proyectos. El análisis cubre cuatro competidores principales. El competidor A tiene fortaleza en integraciones pero debilidad en experiencia móvil. El competidor B lidera en precio pero carece de soporte en español. Se identificaron tres oportunidades de diferenciación: soporte en idioma local, onboarding guiado en menos de 10 minutos y pricing flexible por número de proyectos activos en lugar de por usuario.', 210, 270),
('d4e5f6a7-0004-4000-8000-000000000021', 'c3d4e5f6-0003-4000-8000-000000000021', 'Casos de uso generados para el módulo de autenticación de una aplicación móvil. El caso de uso principal "Inicio de sesión con biometría" incluye las precondiciones de dispositivo con biometría habilitada y sesión expirada, un flujo principal de 6 pasos, dos flujos alternativos para biometría fallida y modo sin conexión, y la postcondición de acceso al dashboard. Las excepciones cubren intentos fallidos repetidos y cierre del sistema operativo durante el proceso.', 170, 220),
('d4e5f6a7-0004-4000-8000-000000000022', 'c3d4e5f6-0003-4000-8000-000000000022', 'Resumen del libro "Thinking, Fast and Slow" de Daniel Kahneman generado. La tesis principal distingue entre el Sistema 1 (pensamiento rápido, automático e intuitivo) y el Sistema 2 (pensamiento lento, deliberado y lógico). Los capítulos clave abordan los sesgos cognitivos más comunes como el efecto ancla, la aversión a la pérdida y el sesgo de disponibilidad. Los aprendizajes prácticos incluyen técnicas para identificar cuándo el Sistema 1 nos lleva a decisiones incorrectas. La aplicación más relevante es en el diseño de procesos de toma de decisiones en equipos de trabajo.', 140, 205),
('d4e5f6a7-0004-4000-8000-000000000023', 'c3d4e5f6-0003-4000-8000-000000000023', 'Variaciones de copy generadas para el botón de CTA de una landing page de SaaS. Variación A: "Empieza gratis hoy" con enfoque en facilidad y sin fricción. Variación B: "Ver cómo funciona en 2 minutos" con enfoque en curiosidad y bajo compromiso. Variación C: "Únete a 12.000 equipos que ya usan la plataforma" con enfoque en prueba social y FOMO. Cada variación incluye una hipótesis sobre el perfil de usuario al que apela y una propuesta de métrica primaria para medir el éxito de la prueba A/B.', 130, 175),
('d4e5f6a7-0004-4000-8000-000000000024', 'c3d4e5f6-0003-4000-8000-000000000024', 'Descripción del esquema de base de datos generada para una plataforma de e-learning. La tabla Users almacena datos del perfil y credenciales con índice en email. La tabla Courses contiene metadatos del curso con índice en instructor_id y categoría. La tabla Enrollments relaciona usuarios con cursos e incluye el campo de progreso como porcentaje. La tabla Lessons pertenece a Courses con ordenamiento por campo position. Se recomienda una tabla separada de UserProgress para evitar actualizaciones frecuentes en Enrollments. Las decisiones de diseño priorizan lectura intensiva sobre escritura.', 200, 265),
('d4e5f6a7-0004-4000-8000-000000000025', 'c3d4e5f6-0003-4000-8000-000000000025', 'Plan de productividad semanal generado. El usuario cuenta con 90 minutos diarios y tiene como objetivo lanzar un proyecto paralelo en 3 meses. El plan asigna lunes y miércoles al desarrollo de producto, martes y jueves a la generación de contenido y validación de mercado, y viernes a revisión semanal de métricas y planificación. Las técnicas recomendadas son Pomodoro de 50 minutos para sesiones de enfoque y time-blocking para proteger el tiempo de trabajo profundo. Las métricas de seguimiento son: tareas completadas por semana, horas de trabajo real vs. planificado y avance en hitos del proyecto.', 170, 235);
